import React, { useState } from 'react';

const App = () => {
  const [hovered, setHovered] = useState(false);
  const [viewMore, setViewMore] = useState(false);

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg[#C06C88] rounded-lg p-4 w-96 shadow-md hover:shadow-lg transition duration-300">
        <h2 className="text-lg font-bold mb-2">Category Card</h2>
        <p className="text-gray-200 mb-4">Sample Category</p>
        <p className="text-gray-200 mb-4">Sample Category Description</p>
        <button className="bg[#B7D7CD] hover:bg[#C06C88] text[#411C56] font-bold py-2 rounded-md w-full" onClick={() => setViewMore(!viewMore)}>View More</button>
        {viewMore && <p className="text-gray-200 mb-4">Sample Category Description Continued</p>}
      </div>
    </div>
  );
};

export default App;
